// ═══════════════════════════════════════════════════════════════════════
//  Astrology Mode
//  - Western zodiac (sign + element) computed from birthday client-side.
//  - Chinese zodiac (animal) computed from birth year client-side.
//  - Famous person born on the same MM-DD fetched live from the Wikipedia
//    REST API (CORS-enabled, no API key) with picture.
//  - Daily advice generated by Ollama via the existing chat endpoint.
// ═══════════════════════════════════════════════════════════════════════

const SIGNS = [
    { name: 'Capricorn',   emoji: '\u2651', element: 'Earth', from: [12, 22], to: [1, 19],  traits: 'disciplined, ambitious, grounded' },
    { name: 'Aquarius',    emoji: '\u2652', element: 'Air',   from: [1, 20],  to: [2, 18],  traits: 'inventive, independent, humanitarian' },
    { name: 'Pisces',      emoji: '\u2653', element: 'Water', from: [2, 19],  to: [3, 20],  traits: 'imaginative, gentle, intuitive' },
    { name: 'Aries',       emoji: '\u2648', element: 'Fire',  from: [3, 21],  to: [4, 19],  traits: 'bold, energetic, pioneering' },
    { name: 'Taurus',      emoji: '\u2649', element: 'Earth', from: [4, 20],  to: [5, 20],  traits: 'patient, reliable, sensual' },
    { name: 'Gemini',      emoji: '\u264A', element: 'Air',   from: [5, 21],  to: [6, 20],  traits: 'curious, witty, adaptable' },
    { name: 'Cancer',      emoji: '\u264B', element: 'Water', from: [6, 21],  to: [7, 22],  traits: 'caring, intuitive, devoted' },
    { name: 'Leo',         emoji: '\u264C', element: 'Fire',  from: [7, 23],  to: [8, 22],  traits: 'warm, generous, charismatic' },
    { name: 'Virgo',       emoji: '\u264D', element: 'Earth', from: [8, 23],  to: [9, 22],  traits: 'analytical, helpful, refined' },
    { name: 'Libra',       emoji: '\u264E', element: 'Air',   from: [9, 23],  to: [10, 22], traits: 'fair, sociable, diplomatic' },
    { name: 'Scorpio',     emoji: '\u264F', element: 'Water', from: [10, 23], to: [11, 21], traits: 'passionate, intense, perceptive' },
    { name: 'Sagittarius', emoji: '\u2650', element: 'Fire',  from: [11, 22], to: [12, 21], traits: 'optimistic, adventurous, philosophical' },
];

const CHINESE = [
    'Monkey', 'Rooster', 'Dog', 'Pig',
    'Rat', 'Ox', 'Tiger', 'Rabbit',
    'Dragon', 'Snake', 'Horse', 'Goat'
];
const CHINESE_EMOJI = {
    Rat: '\uD83D\uDC00', Ox: '\uD83D\uDC02', Tiger: '\uD83D\uDC05', Rabbit: '\uD83D\uDC07',
    Dragon: '\uD83D\uDC09', Snake: '\uD83D\uDC0D', Horse: '\uD83D\uDC0E', Goat: '\uD83D\uDC10',
    Monkey: '\uD83D\uDC12', Rooster: '\uD83D\uDC13', Dog: '\uD83D\uDC15', Pig: '\uD83D\uDC16',
};

export function westernSign(month, day) {
    for (const s of SIGNS) {
        const [fm, fd] = s.from, [tm, td] = s.to;
        // Capricorn wraps the year — handle as two ranges.
        if (fm > tm) {
            if ((month === fm && day >= fd) || (month === tm && day <= td) ||
                (month > fm) || (month < tm)) return s;
        } else {
            if ((month === fm && day >= fd) || (month === tm && day <= td) ||
                (month > fm && month < tm)) return s;
        }
    }
    return SIGNS[0];
}

export function chineseSign(year) {
    // Year-only approximation (true Chinese New Year is late Jan / mid-Feb).
    const animal = CHINESE[year % 12];
    return { animal, emoji: CHINESE_EMOJI[animal] || '' };
}

/**
 * Fetch a famous person born on the same MM-DD using Wikipedia's REST API.
 * The endpoint is CORS-enabled and rate-limited but free; returns up to N
 * candidates that have a thumbnail image.
 */
export async function fetchFamousBirthdayMatch(month, day, max = 3) {
    const mm = String(month).padStart(2, '0');
    const dd = String(day).padStart(2, '0');
    const url = `https://en.wikipedia.org/api/rest_v1/feed/onthisday/births/${mm}/${dd}`;
    const res = await fetch(url, {
        headers: {
            // The Wikipedia REST API asks user agents to identify themselves.
            'Api-User-Agent': 'AI-BABA-G/1.0 (https://github.com/zainabbastahirag/AG_ONE_Fixes)'
        }
    });
    if (!res.ok) throw new Error(`Wikipedia API returned ${res.status}`);
    const data = await res.json();
    const out = [];
    for (const ev of (data.births || [])) {
        const page = (ev.pages || []).find(p => p.thumbnail);
        if (!page) continue;
        out.push({
            year: ev.year,
            text: ev.text,
            title: page.titles?.normalized || page.title?.replace(/_/g, ' ') || 'Famous person',
            extract: page.extract || '',
            thumb: page.thumbnail.source,
            photo: page.originalimage?.source || page.thumbnail.source,
            url: page.content_urls?.desktop?.page || `https://en.wikipedia.org/wiki/${page.title}`,
        });
        if (out.length >= max) break;
    }
    return out;
}

/**
 * Build a structured prompt for Ollama. The bot speaks the daily advice in
 * the user's voice — it is NOT shown the famous person's full biography
 * (we keep it short to avoid hallucinated quotes).
 */
export function buildAdvicePrompt({ name, birthday, sign, chinese, famous }) {
    const youAre = (name || 'the seeker');
    const famousLine = famous?.length
        ? `A famous figure born on the same day is ${famous[0].title} (${famous[0].year}).`
        : '';
    return [
        `You are AI Baba-G as the Astrologer Sage. ${youAre} was born on ${birthday}.`,
        `Western zodiac: ${sign.name} (${sign.element} element) — known for being ${sign.traits}.`,
        `Chinese zodiac animal: ${chinese.animal}.`,
        famousLine,
        `Speak with warmth in 4 short sentences:`,
        ` 1. Greet ${youAre} and acknowledge their sign.`,
        ` 2. One concrete piece of guidance for today (career, focus, or wellbeing).`,
        ` 3. One reflection inspired by the famous figure born the same day (be careful — do NOT invent quotes).`,
        ` 4. A gentle blessing to close.`,
        `No markdown. No bullet points. Pause naturally between sentences.`
    ].filter(Boolean).join('\n');
}
